SELECT sta_id, af_id, gm_id, sta_aqi, sta_pm25, sta_pm10, sta_so2, sta_no2, sta_co, sta_o3, sta_date, sta_time, sta_remark FROM statistics
AND gm_id LIKE CONCAT('%', #{keyword}, '%')
ORDER BY sta_date DESC, sta_time DESC LIMIT #{offset}, #{pageSize}

SELECT sta_id, af_id, gm_id, sta_aqi, sta_pm25, sta_pm10, sta_so2, sta_no2, sta_co, sta_o3, sta_date, sta_time, sta_remark
FROM statistics
WHERE sta_id = #{staId}
